INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (29, 1006058, '使用贴士', '1、请勿将该商品长时间浸泡在液体中，以免长时间浸泡导致木浆脱落，产生碎屑，影响使用；\n2、请勿用沸水浸泡或清洁该商品，以免造成木浆与PP分层，产生碎屑，影响使用；\n3、该商品在不影响使用性能的前提下，可干湿使用，且可重复使用多次，但不具备耐磨性。', 5, NULL);
