INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (43, 1021000, '温馨提示', '1.由于水中含有钙、镁等矿物质，毛巾水洗之后会稍微变硬。定期在含碱/盐/醋的水中蒸煮、浸泡，可使毛巾再次柔软。2.因为毛巾毛圈的丰富性，所以偶尔出现挂线用剪刀剪掉即可，不影响使用，不属于产品质量问题3.为了追求柔软的质感和高吸水性，采用弱捻工艺，可能会有浮毛和少许掉毛，属正常现象。4.该产品为面巾的尺寸，建议面部使用，如需更大尺寸，可选购浴巾。', 6, NULL);
