INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (120, 1096001, '使用说明', '1、该除味皂除味原理为物理作用，不添加香精香氛等，正常可缓解鱼腥异味，但对于严重刺激的特殊异味可能效果不会非常明显，建议辅助香皂或洗手液进行除菌除味；\n2、对气味敏感者慎拍，以免与理想中的预期值存在差距；\n3、除味皂使用多次后表面毛孔会被污渍或水垢等附着，建议定期用较粗糙的百洁布擦洗除味皂表面，清洁除味皂表面“细微毛孔”。', 4, NULL);
