INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (465, 1398011, '温馨提示', '1、生鲜食品一经售出非质量原因，不予退货；\n2、生鲜食品不支持任何形式的拒签，因客户原因如联系方式有误、电话停机、不接电话、无理由拒收等造成快件无法正常签收的情况，不在赔付范围内；\n3、因产品特性原因，蛋制品在运输途中会有蛋壳破损现象产生，真空内袋没有漏气，不影响食用。', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (466, 1398011, '食用建议', '1、建议搭配白粥、米饭、或烹煮菜肴食用；\n2、寒冷环境会导致咸鸭蛋部分脂肪凝固，建议在食用前加热3-5分钟。', 8, NULL);
