INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (530, 1435017, '注意事项', '1、请不要与其他产品同时使用\n2、不是食品，不能食用\n3、避免放在日光直照，高温，多湿的地方，要放在小孩够不到的地方保管\n4、万一被吞入体内时要喝牛奶或水等方法处理。如果不小心弄到眼里时，不要揉，请要马上用水冲洗。\n5、如遇到上述情况，有不舒服时要看医生\n6、溅到皮肤上时要马上用水冲洗\n7、本制品的用途以外请不要使用', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (531, 1435017, '使用重点', '1.请加入200ml温度在80度以上的热水\n2.使用分解剂后，请勿再次冲水，以免影响溶解效果，8小时就可正常放水使用了', 7, NULL);
