INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (540, 1435024, '注意事项', '1.如果猫咪误食豆腐猫砂，对猫咪身体无害。\n2.猫砂开口之后请尽快使用，因为猫砂具有良好的吸水性，所以未使用的猫砂请勿放在阴暗潮湿的环境中，以防止受潮后影响使用效果。\n3.为更好的使用效果，猫砂建议铺垫5-7cm。', 9, NULL);
