INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (575, 1451027, '使用方法', '用户可以根据滤芯颜色判断过滤器的寿命。\n水压明显降低或水色由于锈水、异物等变深，就应该更换过滤器（更换周期可能根据水质不同而有所不同）\n1.转动并分离淋浴头和手把部分\n2.分离旧过滤器和淋浴头\n3.把新过滤器安装到淋浴头\n4.把安装好新过滤器的淋浴头连接到手把', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (576, 1451027, '注意事项', '1.本产品不是医疗品\n2.如长时间使用滤芯，出水量变小，过滤的效果也会降低\n3.此产品是增压除氯负离子淋浴花洒的专用滤芯，通过微沉淀过滤器除去锈和残余氯，还你一个清爽的淋浴感以及健康的皮肤。', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (577, 1451027, '售后说明', '由于净水商品属于消耗产品，滤芯一经拆封使用则无法二次销售。如非商品质量问题，滤芯拆封或已过水，一律无法满足7天无理由退换货政策，敬请谅解', 8, NULL);
