INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (703, 1519011, '售后服务', '1.鞋盒内含干燥剂和防霉片，请家长务必监督远离儿童，防止误食；\n2.鞋头采用宽大空间设计，购买时无需特意拍大一码；\n3.新鞋为避免出现磨脚现象，前几次穿着时建议穿上袜子', 5, NULL);
