INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (708, 1525018, '使用说明', '1、加厚材质，更耐磨；网孔设计，吸附更多尘屑；\n2、无纺布工艺，可一次性使用，也可清洗后重复使用2-4次，弃用时请勿丢弃于马桶，以免堵塞；\n3、干湿两用，干用-静电除尘；湿用-清洁除垢。\n4、地巾尺寸较大，适配于严选懒人拖把', 5, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (709, 1525018, '重量', '约120克/包', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (710, 1540016, '材质说明', '珍珠花纹无纺布、表面活性剂、芦荟护手精华', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (711, 1540016, '贴心提示', '1、厨房清洁湿巾里有添加清洁污渍所需的表面活性剂，所以会产生少量清洁泡沫，此现象为正常现象，非产品质量问题；\n2、此品适用于厨房日常清洁，可擦拭油烟机，燃气灶，台面，水池，如遇到积累较久的“老”油污则需要专业的去油污喷雾来清洁；\n3、建议用厨房湿巾擦拭后再用干净抹布再次清洁一下被擦拭物品，可以减轻物品表面的光滑感，且双重清洁更有益厨房卫生；\n4、此厨房清洁湿巾擦拭物品后表面会有光滑手感，此为市面上通用厨房湿巾基本存在的现象，若有介意者慎拍。', 2, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (712, 1540016, '退货须知', '本商品原则上支持30天内退换货，但是如果产品开封被开启，则默认为已使用，除非有质量问题，否则一经开启无法退货。', 3, NULL);
