INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (815, 1621018, '温馨提示', '1、使用前请先仔细阅读说明书，并进行适当拉伸、热身运动，启动后务必屈膝站立。\n2、用餐前后1小时请勿使用，老人、儿童请在家人监护下使用。\n3、部分人群初次使用时若运动强度过高或时间过长可能出现不良反应，休息片刻即可恢复，强烈建议从低档位开始适应，时间控制在1-3分钟，3天为一个周期逐渐加强加长，机体适应性和前庭功能将在过程中得到提升。\n4、脱鞋使用可增加足底按摩效果。', 10, NULL);
