INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (921, 1674017, '售后说明', '汽车脚垫属于定制产品，原则上不支持30天无忧退换货；\n产品自签收次日起30天内，发生非人为损坏性故障可以申请办理换货服务；', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (922, 1674017, '注意事项', '1、脚垫安装较为复杂，建议去汽车美容店让专业人员安装\n2、皮革层背面的孔是用来固定丝圈的，不与汽车地板自带的孔位重合属正常现象', 2, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (923, 1674017, '定制备注', '请在订单备注中写上您爱车的年款、品牌、车型等信息。例如：2018年款大众高尔夫230TSI豪华型', 3, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (924, 1683030, '尺寸', '30x50cm、38x58cm', 1, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (925, 1683030, '适用季节', '四季', 2, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (926, 1683030, '气味提醒：', '1：采用泰国进口乳胶汁液制成，本身带有淡淡的乳香味，无毒无害，宝宝安心使用；\n2：因礼盒密闭包装，乳胶枕气味可能加重，建议将枕套与枕芯分开，枕芯在阴凉通风处放置3-5天，味道即可挥散淡化，枕套建议清洗后使用。', 3, NULL);
