INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1123, 3459032, '售后服务', '我们承诺按鞋品三包准则进行售后退换货等服务，详情可见内盒三包卡条约。非质量问题的退换货请保持商品整体的清洁，不影响商品的二次销售，否则不予退换，敬请谅解。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1124, 3459032, '温馨提示', '1.选品属于贴身穿搭商品，在收到试穿时请保持商品整体清洁，避免磨损，以方便售后服务。2.因在生产中，需要使用胶水进行粘合，出厂后会稍有气味，但所有异味质检均已符合相关标准检测，如有味道可放置于通风处一到两天即可去除味道。3、一双鞋是由多片多个模具组合而成，生产中多半采用人工手作而成，因此在粘合处难免会有溢胶现象，我们品控也努力将其控制到最小范围，请用户放心购买，也敬请理解。4.不穿时，请妥善', 7, NULL);
