INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1273, 3827027, '温馨提示', '吸尘器释放的臭氧浓度不超过0.05PPM，低于0.1PPM的规定标准，对人体安全无害。但臭氧对人有一定刺激作用，所以需要在无人封闭条件下使用，使用后适当通风即可散去。', 6, NULL);
