INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1331, 3871007, '注意事项', '1.产品生产过程中不可避免会产生轻微的浮毛，属于正常现象，轻拂移除即可，不属于质量问题，请放心使用\n2.该款鞋内里加绒，习惯宽松脚感的，建议选购比正常穿的毛毛虫儿童运动鞋尺码大一码\n3.此款大底采用EVA发泡工艺，大底柔软有弹性，鞋子产品属于手工作业，生产过程中难免会产生大底切口位置变形问题，所以左右脚基本无法控制到完全对称', 5, NULL);
