INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1337, 3884023, '注意事项', '1.本品采用真羊皮毛一体材质，新品会有少量浮毛，属于正常现象，轻拂移除即可；\n2.新的真皮毛纸品会有少许气味，属于正常现象，建议通风处放置一段时间再穿着；\n3.雪地鞋不含鞋垫，可搭配购买羊毛鞋垫，穿着更保暖舒适；\n4.新的雪地靴羊毛质地蓬松，建议按实际脚码购买，以保有适当的贴紧感；随着穿着次数的增加，羊毛会逐渐缩紧，鞋内空间也稍微变得宽松。', 6, NULL);
