INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1499, 3990698, '使用方法', '1.在干净的猫砂盆里铺5-7厘米猫砂；\n2.当猫咪排泄的时候，会迅速吸收并结团，用猫砂铲铲除；\n3.及时添加新猫砂，每月更新，保持5厘米的厚度。\n', 8, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1500, 3990698, '注意事项', '1.本产品为混合猫砂，不可食用；\n2.本产品虽大部分可溶于水，但请勿直接冲入马桶；\n3.猫砂开口之后请尽快使用，因为猫砂具有良好的吸水性，所以未使用的猫砂请勿放在阴暗潮湿的环境中，以防止受潮影响使用效果。\n', 9, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1501, 3990698, '特别提醒', '本产品为真空包装，快递运输过程中可能会产生漏气，但不影响产品使用，介意者慎拍。', 10, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1502, 3990698, '温馨提示', '产品包装上的“6升”标识容量是指产品原料、玉米粉、豆渣等其他所有原料混合在一起的体积，经加工压缩后的成品体积会有部分减少，具体以实际为准。', 11, NULL);
