INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1522, 3991211, '温馨提示', '1：请收藏于干燥、阴凉的地方，避免阳光直射，以免出现菌斑或褪色；2：请勿将丝绸产品直接接触干燥剂、驱虫剂等，以免影响丝绸品质；3：收藏时可平整的置放抽屉中，避免接触尖锐物品，以免勾丝，避免长时间挤压褶皱', 8, NULL);
