INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1527, 3991349, 'Tips跳舞毯功能', '本产品是目前行业内比较优质的跳舞毯，其流畅度和清晰度以及整体产品体验已经过多次迭代升级。其主打的功能是跳舞中趣味运动理念，除出厂配置的200首歌曲外，可以根据需求自行下载更新曲目，本品会同步生成对应的舞步。互动体感游戏和经典游戏是产品附带辅助功能，机器自带125款小游戏，如有需求还可在指定网站下载更新。游戏功能和部分专业做体感游戏的设备有一定差距，产品研发团队也一直在研发更好的国产游戏体验。', 5, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1528, 3991349, 'Tips遥控灵敏度', '如果使用中发现遥控器有偶尔不灵敏状况，首先请查实是否是电池电量不足，建议尝试更换全新电池使用查看。本品属于电子产品，出厂前均经过严格检验合格后发出。但不排除物流运输中损坏内部电路，不可控因素导致灵敏度问题，如您排查后还无法正常使用本品，请及时联系严选客服，会第一时间为您解答。', 6, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1529, 3991349, '款式选购说明', 'PVC童趣与PVC舞动达人，毯面均为PVC材质，配件以及内部软硬件所有配置均一样，仅毯面图案不同。PU家庭悠享的款式，毯面材质为PU，踩踏脚感更舒服，防滑性更优。除此之外，内部软件以及配件配置三款产品完全一致。', 7, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1530, 3991349, '防滑性说明', '跳舞毯底部为EVA材质，具有一定防滑性，但不建议在过于光滑的瓷砖或者木板等地面使用，以免滑动产生安全隐患。将本产品铺在地毯或者其他软垫上使用可降低此困扰，同时可减弱跳动时的噪音对他人的影响。', 8, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1531, 3991349, '游戏界面返回', '因游戏太多各有不同，返回方式主要有以下三种方式（1.切水果返回：用D1手柄，先按Start键暂停，再按selcet返回。2.跑步、乒乓球等很多游戏返回：用手柄先按Start键进拉菜单选择HOME，再按start确认就可以了。3.经典游戏是直接长按3秒按select返回', 9, NULL);
INSERT INTO `goods_prop` (`id`, `goods_id`, `label`, `value`, `sort`, `deleted_at`) VALUES (1532, 3991349, 'HDMI线说明', '跳舞毯本身是无线控制，出厂配置的HDMI线约1M左右。该HDMI线用于连接电视机和机顶盒。放置机顶盒的位置控制在电视机附近1M范围内即可。如HDMI线不够长，可自行购买符合国家3C标准的加长HDMI线。HDMI接口适配型号：标准接口，宽约14mm；厚约4.5mm。', 10, NULL);
